import { useState } from "react";
import { KanbanBoard } from "../../components/kanban/KanbanBoard";
import { boardConfig } from "./config";
import { initialCards } from "./data";
import { useDraggableColumnsBoardCardChange, useDraggableColumnsBoardLoadMore } from "./useCardChange";
import type { KanbanCardData, KanbanColumnConfig } from "./types";

/**
 * Workflow — drag columns to reorder
 * Grab a column header to reorder it; cards remain draggable inside
 *
 * Drag-and-drop is powered by the project's custom Pointer DnD library
 * (no @dnd-kit dependency). Cards persist locally — wire `useCardChange`
 * to your backend to make moves stick across reloads.
 *
 * Column reordering is enabled: dragging a column header rearranges the
 * board. Local `columns` state mirrors the order so the change persists
 * across re-renders. Replace with a server PATCH for production.
 */
export default function DraggableColumnsBoard() {
  const [cards, setCards] = useState<KanbanCardData[]>(initialCards);
  const [columns, setColumns] = useState<KanbanColumnConfig[]>(boardConfig.columns);
  const handleCardChange = useDraggableColumnsBoardCardChange();
  const handleLoadMore = useDraggableColumnsBoardLoadMore();
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-xl font-bold">{boardConfig.title}</h2>
        {boardConfig.subtitle && (
          <p className="text-sm text-muted-foreground">{boardConfig.subtitle}</p>
        )}
      </div>
      <KanbanBoard
        config={{ ...boardConfig, columns }}
        cards={cards}
        onCardsChange={setCards}
        onColumnsChange={setColumns}
        onCardChange={handleCardChange}
        onLoadMore={handleLoadMore}
      />
    </div>
  );
}

